const crypto = require('crypto');

const item = $input.first().json;
const executionId = `exec_${Date.now()}_${crypto.randomBytes(4).toString('hex')}`;

return [{
  json: {
    execution_id: executionId,
    script: item.script,
    callback_url: item.callback_url,
    config: {
      parallel_scenes: item.config?.parallel_scenes || 5,
      image_resolution: item.config?.image_resolution || '2K',
      video_model: item.config?.video_model || 'kling-2.6',
      transition_type: item.config?.transition_type || 'crossfade',
      output_resolution: item.config?.output_resolution || '1080p'
    },
    started_at: new Date().toISOString()
  }
}];

