const allResults = $input.all();

const videos = allResults
  .filter(item => {
    const data = item.json.body || item.json;
    return data.success === true;
  })
  .map(item => {
    const data = (item.json.body || item.json).data || item.json.body || item.json;
    return {
      scene_id: data.scene_id,
      video_url: data.video_url,
      duration_seconds: data.duration_seconds,
      order: data.scene_id
    };
  });

const failed = allResults.filter(item => {
  const data = item.json.body || item.json;
  return data.success !== true;
});

if (failed.length > 0) {
  console.log(`Warning: ${failed.length} scenes failed video generation`);
}

return [{
  json: {
    scene_videos: videos.sort((a, b) => a.order - b.order),
    successful_count: videos.length,
    failed_count: failed.length
  }
}];

